INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$RESTful API and SMTP relay$q$, $q$Send transactional and marketing email through a modern REST API or a standard SMTP relay, whichever fits the existing stack.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$React Email integration$q$, $q$Build emails as React components using the open-source React Email library, which Resend also maintains.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Official SDKs$q$, $q$First-party SDKs for Node.js, Python, PHP, Ruby, Go, Java, and Rust simplify integration.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Inbound email parsing$q$, $q$Receive and parse inbound email, not just send outbound messages.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Batch sending and webhooks$q$, $q$Send emails in bulk and receive real-time delivery, bounce, and engagement events via webhooks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Deliverability tooling$q$, $q$Built-in DKIM, SPF, and DMARC authentication plus optional dedicated IPs with automatic warmup on the Scale plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Open and click tracking$q$, $q$Track opens and link clicks across sent campaigns and transactional messages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$SOC 2 Type II and GDPR compliance$q$, $q$Enterprise-grade security and compliance posture with MFA and granular API key permissions.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Clean, modern developer experience with well-documented API and SDKs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Deep React Email integration for building emails in JSX$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Generous free tier for small projects (3,000 emails/month)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Fast setup for transactional email in Node.js/TypeScript stacks$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Strong deliverability tooling included out of the box$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Enterprise-scale pricing requires contacting sales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$2024 price increases on higher Scale tiers upset some long-time customers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Marketing/broadcast features are billed separately from transactional email$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Newer platform than incumbents like SendGrid or Mailgun, so track record is shorter$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Daily send cap on the free plan (100 emails/day) limits testing at scale$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Is Resend free to use?$q$, $q$Yes, Resend offers a free tier covering 3,000 emails per month, capped at 100 emails per day on one domain.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$What is Resend used for?$q$, $q$Resend is used to send transactional email (receipts, password resets, OTPs) and marketing broadcasts from applications via API or SMTP.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Does Resend integrate with React Email?$q$, $q$Yes, Resend created and maintains React Email and offers native integration for building emails as React components.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$How much does Resend cost?$q$, $q$Paid plans start at $20/month for Pro (50,000 emails), scaling up to $1,150/month for Scale (2.5 million emails), with custom Enterprise pricing above that.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Does Resend support SMTP?$q$, $q$Yes, alongside its REST API, Resend offers a standard SMTP relay for sending email.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$When was Resend founded and where is it based?$q$, $q$Resend was founded in 2022 and is headquartered in San Francisco, California.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Does Resend offer dedicated IPs?$q$, $q$Yes, dedicated IPs are available as a $30/month add-on for Scale plan customers sending more than 3,000 emails per day.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Is Resend SOC 2 and GDPR compliant?$q$, $q$Yes, Resend holds SOC 2 Type II certification and is GDPR compliant.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Transactional email for SaaS products$q$, $q$Send order confirmations, password resets, and one-time codes reliably via API or SMTP.$q$, $q$Software engineering and product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Marketing newsletters and broadcasts$q$, $q$Send contact-based newsletters and campaigns using Resend's separate marketing pricing track.$q$, $q$Marketing and growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Product notification systems$q$, $q$Build automated, high-deliverability notification flows integrated directly into application code.$q$, $q$Startups and developer teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["3,000 emails/month","100 emails/day cap","1 domain","RESTful API and SMTP relay","5 AI credits/month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Pro$q$, $q$$20-$35/month$q$, $q$monthly$q$, NULL, $q$["50,000-100,000 emails/month","10 domains","No daily cap","100 AI credits/month","$0.90 per 1,000 overage emails"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Scale$q$, $q$$90-$1,150/month$q$, $q$monthly$q$, NULL, $q$["100,000-2,500,000 emails/month","1,000 domains","Dedicated IP add-on ($30/month)","Slack and ticket support","500 AI credits/month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["3M+ emails/month","Priority support","Flexible domains and AI credits","Custom automation limits"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Resend is an email API and SMTP platform built specifically for developers, founded in 2022 and headquartered in San Francisco. It combines a RESTful API, SMTP relay, official SDKs, and the React Email component library into a single toolkit for sending both transactional and marketing email from modern application stacks.$q$, $q$Backed by notable angel investors from Figma, Vercel, and Supabase, and later an Andreessen Horowitz-led Series A, Resend has grown into a widely used alternative to legacy email service providers, particularly among teams already working in JavaScript and TypeScript.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Resend's core feature set covers the full transactional email lifecycle: a RESTful API and SMTP relay for sending, inbound email parsing for receiving, batch sending for volume, and webhooks and open/click tracking for monitoring delivery and engagement.$q$, $q$Deliverability is handled through built-in DKIM, SPF, and DMARC authentication, multi-region sending infrastructure, and optional dedicated IPs on higher tiers, while security and compliance are covered by SOC 2 Type II certification, GDPR compliance, multi-factor authentication, and granular API key permissions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Resend uses a freemium, usage-based pricing model split across four tiers. The Free plan covers 3,000 emails per month (100/day, 1 domain). Pro costs $20/month for 50,000 emails or $35/month for 100,000 emails. Scale ranges from $90 to $1,150/month for 100,000 to 2.5 million emails, adding dedicated IPs, 1,000 domains, and Slack support. Enterprise is custom-priced for 3M+ emails per month.$q$, $q$A separate marketing email track bills by number of contacts rather than emails sent, running from roughly $40/month up to $650/month depending on list size for teams sending newsletters and broadcasts through the same account.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Peer-to-peer (BitTorrent-protocol) file transfer$q$, $q$Syncs files directly between devices using an optimized BitTorrent protocol instead of routing through central cloud servers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Selective sync and folder-level control$q$, $q$Choose exactly which folders and files sync to which devices.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$NAS and server sync support$q$, $q$Works with a wide range of NAS devices and servers, not just desktop and mobile apps.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$File versioning and conflict resolution$q$, $q$Keeps prior file versions and handles sync conflicts automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Cross-platform apps$q$, $q$Available for Windows, Mac, Linux, iOS, Android, and NAS platforms.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$One-time license option for individuals$q$, $q$Sync Home Pro is a non-subscription, one-time purchase rather than a recurring fee.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Business management features$q$, $q$Sync Business adds centralized management, LDAP/AD integration, and audit logging.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Cloud-free operation$q$, $q$Files can sync entirely without being stored on third-party cloud infrastructure.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$No recurring subscription needed for individual Home Pro license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Fast large-file transfers using P2P protocol, good for media-heavy workflows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Keeps files off third-party cloud storage for privacy and data-sovereignty reasons$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Cross-platform support including NAS devices$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Effective for syncing very large files and folders such as video and RAW photos$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Business pricing is not published and requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Requires devices to be online, or relay servers, for real-time sync unlike always-on cloud storage$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Acquired by Nasuni in 2026, creating uncertainty about the product's long-term roadmap$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Less mainstream name recognition than Dropbox, Google Drive, or OneDrive$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Folder-sharing model is less intuitive for non-technical users than typical cloud drives$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$What is Resilio Sync?$q$, $q$Resilio Sync is a peer-to-peer file synchronization tool that syncs files directly between devices using BitTorrent-protocol technology, without requiring cloud storage.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Is Resilio Sync free?$q$, $q$Yes, Sync Home is free with basic functionality; Sync Home Pro is a one-time $59.99 purchase for expanded features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$How is Resilio Sync different from Dropbox or Google Drive?$q$, $q$Resilio Sync transfers files directly between devices peer-to-peer rather than storing a copy on third-party cloud servers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$How much does Resilio Sync Home Pro cost?$q$, $q$Sync Home Pro is a one-time, non-subscription license priced at $59.99.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Does Resilio Sync work with NAS devices?$q$, $q$Yes, Resilio Sync supports a wide range of NAS devices in addition to desktop and mobile platforms.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Who owns Resilio Sync now?$q$, $q$Resilio was acquired by cloud file services company Nasuni in March 2026.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Is there a Resilio Sync business plan?$q$, $q$Yes, Resilio Sync Business is a subscription product with custom, sales-gated pricing for teams.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Does Resilio Sync store my files in the cloud?$q$, $q$No, by default Resilio Sync transfers files directly between devices rather than storing them on third-party cloud servers.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Media and creative file syncing$q$, $q$Sync large video, photography, and CAD files between studios and freelance collaborators without cloud storage costs.$q$, $q$Creative and media production teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Subscription-free personal file sync$q$, $q$Keep files in sync across all of one person's devices with a single one-time purchase instead of a recurring fee.$q$, $q$Individuals and freelancers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Private cross-office file distribution$q$, $q$Distribute files between business locations directly without routing through third-party cloud infrastructure.$q$, $q$Businesses with multiple offices or field teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Sync Home$q$, $q$$0$q$, $q$free$q$, NULL, $q$["Basic peer-to-peer folder sync","Limited device count","Cross-platform apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Sync Home Pro$q$, $q$$59.99$q$, $q$one-time$q$, NULL, $q$["Unlimited devices for one person","Selective sync","File versioning","Sync to cloud/NAS storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$Sync Business$q$, $q$Custom$q$, $q$subscription (contact sales)$q$, NULL, $q$["Centralized management","LDAP/Active Directory integration","Audit logging","Transitioning to Resilio Active Everywhere"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Resilio Sync originated as BitTorrent Sync inside BitTorrent Inc. before being spun out as an independent company, Resilio, in 2016. It uses peer-to-peer BitTorrent-protocol technology to sync files directly between devices rather than routing them through a central cloud server.$q$, $q$The product line covers individuals (Sync Home and Sync Home Pro) and businesses (Sync Business, transitioning to Resilio Active Everywhere), with Resilio acquired by cloud file platform Nasuni in March 2026.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Resilio Sync supports selective folder sync, file versioning, and cross-platform apps for Windows, Mac, Linux, iOS, Android, and many NAS devices, enabling fast transfer of very large files without a cloud storage intermediary.$q$, $q$Business deployments add centralized management, LDAP/Active Directory integration, and audit logging, targeting organizations that need private, point-to-point file distribution across offices.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44084df6-f4d6-4a50-9b62-fd348ba43737', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Individuals can use Sync Home for free with basic functionality, or purchase Sync Home Pro as a one-time $59.99 lifetime license covering unlimited devices for one person, with no recurring subscription.$q$, $q$Resilio Sync Business pricing is not published; it is a sales-gated, subscription-based product that requires contacting Resilio directly for a custom quote based on team size and required features.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Drag-and-drop scheduling calendar$q$, $q$Visually schedule people, equipment, and rooms on one shared calendar.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Leave management$q$, $q$Track team availability and time off alongside project bookings.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Custom fields and filters$q$, $q$Filter and match resources by skills, location, or other custom attributes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Timesheets$q$, $q$Available on Blackbelt and above for tracking time against projects.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Project budgets, rates and milestones$q$, $q$Track project financials and key dates on Blackbelt and above.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Approval workflows and SSO$q$, $q$Available on the Master plan for larger, governance-focused teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Calendar sync$q$, $q$Sync bookings with Google Calendar, Outlook, and iCal.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Reporting and utilization dashboards$q$, $q$Customizable reports to track team capacity and utilization.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Simple, purpose-built scheduling UI that's fast to learn$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Affordable per-user pricing with a generous free trial$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Handles people, equipment, and rooms in one calendar$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Strong clash and overbooking prevention$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Reduced pricing for non-human resources like equipment and rooms$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Not a full project management tool, no task boards or Gantt charts in the core product$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$SSO and approval workflows are locked to the top Master tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Per-user pricing can add up for larger teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Reporting and analytics depth is lighter than dedicated PM or BI suites$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$No native time-tracking beyond the Blackbelt-and-above timesheets$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$What is Resource Guru used for?$q$, $q$Resource Guru is used for scheduling and booking people, equipment, and meeting rooms to avoid overbooking and manage team capacity.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$How much does Resource Guru cost?$q$, $q$Plans range from $5 to $12 per user per month billed monthly, or $4.16 to $10 per user per month billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Is there a free trial?$q$, $q$Yes, Resource Guru offers a 30-day free trial with no credit card required.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Does Resource Guru do timesheets?$q$, $q$Yes, timesheets are included on the Blackbelt plan and above.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Can I schedule equipment and rooms, not just people?$q$, $q$Yes, Resource Guru supports scheduling equipment and rooms as resources, billed at a lower rate than people.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Does Resource Guru support SSO?$q$, $q$Yes, single sign-on is available on the Master plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Who is Resource Guru for?$q$, $q$It's designed for agencies, consultancies, and professional services teams that need visual resource scheduling.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Can I cancel my Resource Guru subscription anytime?$q$, $q$Yes, users can upgrade, downgrade, or cancel at any time with no setup fees.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Creative and marketing agencies$q$, $q$Schedule staff across multiple client projects and prevent double-booking.$q$, $q$Agency resource managers and project leads$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Engineering and architecture firms$q$, $q$Book specialists and shared equipment for project timelines.$q$, $q$Studio and firm operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Professional services teams$q$, $q$Track capacity and utilization across consultants and billable staff.$q$, $q$Consulting and professional services managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Grasshopper$q$, $q$$5/month ($4.16/month annual)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited projects and clients","Personalized dashboards","Custom filters","Calendar sync","1 free placeholder","7-day activity history"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Blackbelt$q$, $q$$8/month ($6.67/month annual)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Grasshopper","Timesheets","Customizable reports","Project dates and milestones","Project rates and budgets","10 custom fields","5 free placeholders"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$Master$q$, $q$$12/month ($10/month annual)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Blackbelt","Approval workflow","SSO","Unlimited activity history and custom fields","Phone support","10 free placeholders"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Resource Guru is a cloud-based scheduling tool founded in 2011 and based in London, purpose-built for booking people, equipment, and rooms on a single visual calendar rather than managing full project tasks.$q$, $q$It's aimed at agencies, consultancies, and professional services teams that need clear, fast visibility into who and what is available, with clash detection to prevent double-booking.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core is a drag-and-drop scheduling calendar supporting people, equipment, and meeting rooms, with leave management, custom fields, and calendar sync to Google, Outlook, and iCal.$q$, $q$Higher tiers add timesheets, project budgets and rates, approval workflows, and single sign-on, plus reporting and utilization dashboards for tracking team capacity.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('10489d53-8568-4993-9c9f-4e97a69b327b', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Resource Guru has three per-user tiers: Grasshopper at $5/month ($4.16 annually), Blackbelt at $8/month ($6.67 annually), and Master at $12/month ($10 annually), each unlocking progressively more features.$q$, $q$Equipment and room resources are billed at a discounted rate compared to human users, and all plans include a 30-day free trial with no credit card required.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Open-source, self-hostable DAM core$q$, $q$Download and run the full platform on your own servers with no license fee.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Managed cloud hosting option$q$, $q$Tiered cloud plans hosted in London Docklands data centers for teams that don't want to self-host.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$AI-assisted tagging and search$q$, $q$Automatic tagging, face detection, and natural-language search on paid cloud tiers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Metadata schemas and custom fields$q$, $q$Configure detailed metadata structures for organizing large asset libraries.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$SSO and API access$q$, $q$Available on paid cloud tiers for enterprise integration and authentication.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Usage rights and licensing tracking$q$, $q$Track asset rights, licensing terms, and watermarking for compliance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$SFTP drop folder$q$, $q$Bulk ingest assets via SFTP rather than manual uploads.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Public access portals$q$, $q$Share assets externally through public-facing portals on Business tier and above.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Free, unrestricted open-source self-hosting option$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$No per-user licensing costs for self-hosted deployments$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Managed cloud option removes hosting and maintenance burden$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Strong metadata, tagging, and rights-management features for enterprise DAM needs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Employee-owned, B Corp maintainer with a transparent company structure$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Self-hosting requires in-house technical resources to install, secure, and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Cloud plan pricing is not fully published for all tiers; larger tiers need a custom quote$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Interface is less modern-looking than some venture-backed commercial DAM competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$AI features are limited primarily to paid cloud tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Smaller support and services team compared to larger commercial DAM vendors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Is ResourceSpace really free?$q$, $q$Yes, ResourceSpace is open source and can be self-hosted for free with no license fee or user limits.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$What is ResourceSpace used for?$q$, $q$ResourceSpace is used as a digital asset management system to store, tag, search, and control access to images, video, and documents.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Who makes ResourceSpace?$q$, $q$ResourceSpace is maintained by Montala Limited, a UK-based, employee-owned company founded by original creator Dan Huby.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Does ResourceSpace offer cloud hosting?$q$, $q$Yes, Montala offers a free cloud tier plus paid Team, Business, Enterprise, and Platinum cloud hosting tiers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$How much does ResourceSpace cloud hosting cost?$q$, $q$Paid cloud plans range from around $358/month for Team Cloud up to around $1,357/month for Enterprise Cloud, with custom Platinum pricing above that.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Does ResourceSpace have AI features?$q$, $q$Yes, paid cloud plans include AI-assisted auto-tagging, face detection, and natural-language search.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Can I self-host ResourceSpace?$q$, $q$Yes, ResourceSpace is open source and designed to be self-hosted on your own infrastructure.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Does ResourceSpace support single sign-on?$q$, $q$Yes, SSO is available on the paid cloud hosting plans.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Institutional media libraries$q$, $q$Universities and nonprofits self-host a free DAM for institutional images, video, and documents.$q$, $q$Universities and charities$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Brand asset management$q$, $q$Marketing and creative teams use managed cloud DAM to organize and distribute brand asset libraries.$q$, $q$Marketing and creative teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Rights-managed digital collections$q$, $q$Museums and archives manage rights-tracked collections with public-facing access portals.$q$, $q$Museums and archival institutions$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Self-Hosted (Open Source)$q$, $q$$0$q$, $q$free, self-hosted$q$, NULL, $q$["Full DAM platform source code","No per-user license fee","Unlimited users (self-managed infrastructure)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Free Cloud$q$, $q$$0$q$, $q$free$q$, NULL, $q$["10GB storage","Up to 10 users"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Team Cloud$q$, $q$~$358/month$q$, $q$monthly or annual (~$5,108/year)$q$, NULL, $q$["25 users","1-9TB storage","AI tools, SSO, API access","Dedicated server"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Business Cloud$q$, $q$~$778/month$q$, $q$monthly or annual (~$11,500/year)$q$, NULL, $q$["100 users plus optional public access","3-15TB storage","AI tools, SSO, API access"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Enterprise Cloud$q$, $q$~$1,357/month$q$, $q$monthly or annual (~$20,355/year)$q$, NULL, $q$["500 users","8-20TB storage","Priority support"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$Platinum Cloud$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Unlimited users","50TB-plus storage","Priority support"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ResourceSpace was created in 2006 by Dan Huby and Neale Hall while contracting for the charity Oxfam, which released the resulting DAM software under an open-source license. Huby later founded Montala Limited, an employee-owned UK company that maintains ResourceSpace and hosts its managed cloud service.$q$, $q$Because the core product is open source, organizations can self-host ResourceSpace for free with no per-user license fees, or choose Montala's managed cloud hosting for a fully supported experience.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ResourceSpace covers the core DAM workflow: upload, tag, search, and control access to images, video, and documents, with metadata schemas, custom fields, watermarking, and usage rights tracking.$q$, $q$Paid cloud tiers add AI-assisted automatic tagging, face detection, and natural-language search, plus SSO, API access, SFTP drop folders for bulk ingest, and public access portals for external sharing.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00400667-6209-4172-b7aa-b8106d654692', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Self-hosting ResourceSpace is completely free with no license cost or user limits. A free cloud tier offers 10GB of storage for up to 10 users.$q$, $q$Paid cloud hosting runs from around $358/month (Team Cloud, 25 users) up to around $1,357/month (Enterprise Cloud, 500 users), with a custom-quoted Platinum Cloud tier for unlimited users and 50TB-plus storage.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('00400667-6209-4172-b7aa-b8106d654692', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Unified omnichannel inbox$q$, $q$Manage WhatsApp, Messenger, Instagram, Telegram, SMS, email, and web chat conversations from one inbox.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$AI Agents$q$, $q$Deploy AI-driven auto-responders and lead-qualification bots directly inside conversations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Workflow automation builder$q$, $q$Build automated routing, tagging, and follow-up workflows across channels.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Broadcast and campaign messaging$q$, $q$Send bulk messages and campaigns to segmented contact lists.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Team collision avoidance$q$, $q$Prevent multiple agents from replying to the same conversation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$MAC-based contact management$q$, $q$Pricing and limits are based on Monthly Active Contacts messaged during a billing period.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Reporting and analytics$q$, $q$Dashboards for tracking response times, team performance, and conversation volume.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Integrations$q$, $q$Connects with Zapier, Make, Salesforce, webhooks, and a developer API.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$True omnichannel unification across most major messaging apps including WhatsApp$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$AI Agents and AI Assist reduce manual reply workload$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Flexible workflow automation for lead routing and qualification$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Unlimited MACs on the Starter plan for lower-volume teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Strong fit for WhatsApp-heavy markets like Southeast Asia, Latin America, and the Middle East$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$MAC-based pricing model can be confusing and lead to unexpected overage charges on higher tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Broadcasts, workflows, and AI Agents are locked out of the entry-level Starter plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Meta/WhatsApp messaging fees are billed separately on top of the subscription cost$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$SSO and Salesforce integration require the Advanced tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Free trial is limited to 7 days$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$What is respond.io used for?$q$, $q$Respond.io is used to unify messaging channels like WhatsApp, Messenger, and Instagram into one inbox for sales and customer support teams.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$How much does respond.io cost?$q$, $q$Plans range from $79/month (Starter) to $279/month (Advanced) billed annually, with custom Enterprise pricing above that.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$What is a Monthly Active Contact (MAC)?$q$, $q$A MAC is a unique contact a business messages within a billing period, and it's the core usage metric respond.io's pricing is based on.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Does respond.io support WhatsApp?$q$, $q$Yes, respond.io integrates with the official WhatsApp Business API alongside other messaging channels.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Does respond.io have AI features?$q$, $q$Yes, it offers AI Agents for automated conversation handling and AI Assist to help agents draft replies.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Is there a free trial?$q$, $q$Yes, respond.io offers a 7-day free trial with Growth-plan features.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Does respond.io integrate with Salesforce?$q$, $q$Yes, Salesforce integration is available starting on the Advanced plan.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Where is respond.io based?$q$, $q$Respond.io is headquartered in Kuala Lumpur, Malaysia, and was founded in 2017.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$E-commerce customer support$q$, $q$Manage WhatsApp and Instagram customer support conversations at scale from one inbox.$q$, $q$E-commerce support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$AI-assisted lead qualification$q$, $q$Route and qualify inbound leads across messaging channels using AI Agents and workflow automation.$q$, $q$B2B sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Broadcast campaigns and follow-ups$q$, $q$Run broadcast messaging campaigns and automated follow-up sequences.$q$, $q$Real estate and service businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Starter$q$, $q$$79/month annual ($99/month monthly)$q$, $q$monthly or annual$q$, NULL, $q$["5 users","Unlimited Monthly Active Contacts","Team inboxes, mobile app","No broadcasts, workflows, or AI Agents"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Growth$q$, $q$$159/month annual ($199/month monthly)$q$, $q$monthly or annual$q$, NULL, $q$["10 users","From 1,000 MACs","Broadcasts, workflow automation, AI Agents","Zapier and Make integrations","Developer API"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Advanced$q$, $q$$279/month annual ($349/month monthly)$q$, $q$monthly or annual$q$, NULL, $q$["10 users","From 1,000 MACs","SSO, Salesforce integration","Multiple workspaces","Webhook/HTTP workflow steps"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Unlimited users","Higher API limits","Dedicated success manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Respond.io is a business messaging platform founded in 2017 and headquartered in Kuala Lumpur, Malaysia, that unifies channels like WhatsApp, Messenger, Instagram, and Telegram into a single shared inbox for sales and support teams.$q$, $q$The company has raised roughly $71.3 million, including a $62.5 million Series B in June 2026, and has increasingly focused on AI Agents that automate conversation handling and lead qualification.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's core is an omnichannel inbox spanning WhatsApp Business API, Messenger, Instagram, Telegram, SMS, email, and web chat, with routing rules and team collision-avoidance to prevent duplicate replies.$q$, $q$AI Agents and AI Assist automate and accelerate replies, while workflow automation, broadcast messaging, and integrations with Zapier, Make, and Salesforce extend the platform for sales and marketing use cases.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5ba6eb3b-9e95-46c8-907b-8f15ea5b72ae', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Respond.io prices plans by user seats and Monthly Active Contacts (MACs). Starter costs $79/month annually with unlimited MACs but no automation; Growth costs $159/month annually with automation and AI Agents starting at 1,000 MACs; Advanced costs $279/month annually and adds SSO and Salesforce integration.$q$, $q$Overage fees apply once MAC limits are exceeded on Growth and Advanced, and Meta/WhatsApp messaging costs are billed separately from the respond.io subscription. Enterprise pricing is custom.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Restaurant-specific accounting$q$, $q$AP automation, banking, financial reporting, and multi-entity consolidation built for restaurant chart-of-accounts needs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Recipe-level inventory costing$q$, $q$Track ingredient costs, vendor purchasing, and waste at the recipe level.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Labor scheduling and workforce management$q$, $q$Schedule staff, track time, and forecast labor costs across locations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Integrated payroll and HR$q$, $q$Process payroll and manage hiring and onboarding within the same platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Multi-location financial consolidation$q$, $q$Consolidate P&L and financial reporting across many restaurant locations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$POS integrations$q$, $q$Connects with major POS systems including Toast, Square, and Clover.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Business analytics dashboards$q$, $q$Custom financial reporting and analytics on the Professional tier.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Fixed asset tracking$q$, $q$Track fixed assets across locations, included on the Professional tier.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Purpose-built for restaurant accounting complexity like recipe costing and prime cost tracking$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Combines accounting, inventory, scheduling, and payroll in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Unlimited users per location on published plan tiers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Broad POS and vendor integrations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Strong fit for multi-unit and multi-concept restaurant groups$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$No published self-serve pricing; requires a sales conversation for a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Per-location pricing can be expensive for small independent restaurants$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Implementation and onboarding can be complex given the breadth of modules$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Reported employee and company-size figures vary significantly across data sources$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Full value requires adopting multiple modules, which raises total cost$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$What is Restaurant365 used for?$q$, $q$Restaurant365 is used as an all-in-one back-office platform for restaurant accounting, inventory, scheduling, and payroll.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$How much does Restaurant365 cost?$q$, $q$Pricing is custom-quoted, but industry estimates put plans in the range of roughly $469 to $749 per location per month depending on tier.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Does Restaurant365 include payroll?$q$, $q$Yes, payroll and HR are available as part of Restaurant365's product suite.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Does Restaurant365 integrate with my POS?$q$, $q$Yes, it integrates with major POS systems including Toast, Square, and Clover.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Is Restaurant365 for single restaurants or chains?$q$, $q$It's built primarily for multi-unit and multi-concept restaurant operators, though single locations can also use it.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$When was Restaurant365 founded?$q$, $q$Restaurant365 was founded in 2011.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Where is Restaurant365 headquartered?$q$, $q$Restaurant365 is headquartered in Irvine, California.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Does Restaurant365 offer a free trial?$q$, $q$No public self-serve free trial is listed; prospects request a demo and custom quote from sales.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Multi-unit accounting consolidation$q$, $q$Consolidate accounting and financial reporting across many restaurant locations.$q$, $q$Restaurant group CFOs and controllers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Recipe-level food costing$q$, $q$Track inventory and food costs at the recipe level to manage prime cost.$q$, $q$Restaurant operations and culinary teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Scheduling and payroll management$q$, $q$Manage staff scheduling, time tracking, and payroll in one system.$q$, $q$Restaurant HR and operations managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Essential (industry estimate)$q$, $q$~$469-499/location/month$q$, $q$custom quote$q$, NULL, $q$["POS Connect","R365 Accounting","AP Automation","Inventory","Scheduling","Recipe costing","Smart Labor, Smart Ordering, Smart Prep"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Professional (industry estimate)$q$, $q$~$689-749/location/month$q$, $q$custom quote$q$, NULL, $q$["Everything in Essential","Business Analytics","Custom financial reports","Fixed asset tracking"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$Enterprise/Custom$q$, $q$Custom$q$, $q$custom quote$q$, NULL, $q$["Tailored module selection","Custom implementation and support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Restaurant365 is a restaurant-specific back-office platform founded in 2011 and headquartered in Irvine, California, built to unify accounting, inventory, scheduling, and payroll for multi-unit restaurant operators.$q$, $q$Backed by roughly $445 million in funding and valued at over $1 billion, the company has scaled to serve tens of thousands of restaurant locations, though pricing and exact headcount are not fully public.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's core modules cover restaurant-specific accounting and AP automation, recipe-level inventory costing and purchasing, labor scheduling, and integrated payroll and HR, all built around multi-location financial consolidation.$q$, $q$It integrates with major POS systems like Toast, Square, and Clover, and adds business analytics dashboards and fixed asset tracking on its higher Professional tier.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9db567bc-79c1-40cb-a4a7-632f1cdc6fde', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Restaurant365 does not publish self-serve pricing; the official pricing page routes prospects to a custom quote via sales, demo, or email contact.$q$, $q$Third-party industry estimates commonly cite an Essential tier around $469-499 per location per month and a Professional tier around $689-749 per location per month, both reportedly with unlimited user seats per location.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Client-side AES-256 encryption$q$, $q$All backup data is encrypted before it leaves the source machine.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Deduplication via content-defined chunking$q$, $q$Only changed portions of files are stored and transferred on each backup.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Snapshot-based incremental backups$q$, $q$Efficient, point-in-time snapshots that build on previous backups.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Built-in backup verification$q$, $q$Commands to check repository integrity and verify restores actually work.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Wide backend support$q$, $q$Works with local disks, SFTP, S3, Backblaze B2, Azure, Google Cloud, and more via rclone.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Cross-platform single binary$q$, $q$Runs on Linux, macOS, Windows, FreeBSD, and OpenBSD with no separate install.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Scriptable CLI$q$, $q$Suited for automation via cron jobs, systemd timers, or CI/CD pipelines.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Free and open source$q$, $q$Released under the BSD 2-Clause license with no cost or vendor lock-in.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Completely free with no subscription or paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Strong encryption and deduplication built in by default$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Wide range of supported storage backends, including via rclone$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Verifiable backups reduce the risk of silent backup corruption$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Lightweight single-binary install that's easy to automate via scripts or cron$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$No official graphical user interface, command-line only$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$No official vendor support; relies on community forums and GitHub issues$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Steeper learning curve for non-technical users compared to consumer backup apps$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$No built-in scheduling; must be paired with cron, systemd timers, or third-party wrappers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$No managed storage included; users must bring and pay for their own backend$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Is restic free?$q$, $q$Yes, restic is completely free and open source with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$What license does restic use?$q$, $q$Restic is released under the BSD 2-Clause license.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$What storage backends does restic support?$q$, $q$Local disks, SFTP, a REST server, Amazon S3, Backblaze B2, Azure Blob Storage, Google Cloud Storage, and many more via rclone.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Does restic encrypt backups?$q$, $q$Yes, all data is encrypted client-side using AES-256 before it's stored.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Does restic have a graphical user interface?$q$, $q$Not officially; restic is a command-line tool, though third-party GUIs exist.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$What platforms does restic support?$q$, $q$Linux, macOS, Windows, FreeBSD, and OpenBSD.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Who maintains restic?$q$, $q$Restic was created by Alexander Neumann and is maintained by a small core team and community contributors on GitHub.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$How do I schedule restic backups?$q$, $q$Restic has no built-in scheduler; users typically pair it with cron, systemd timers, or third-party wrapper tools.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Automated encrypted server backups$q$, $q$Sysadmins automate backups of servers to S3 or Backblaze B2 via cron with client-side encryption.$q$, $q$Sysadmins and DevOps engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Self-hosted NAS and home server backups$q$, $q$Back up NAS or home server data to cloud object storage without a subscription.$q$, $q$Self-hosters and home lab users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Scriptable developer and CI backups$q$, $q$Integrate verifiable, scriptable backups into development workflows and CI/CD pipelines.$q$, $q$Developers and technical teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$Open Source$q$, $q$$0$q$, $q$free, unlimited use$q$, NULL, $q$["Full backup and restore functionality","Client-side AES-256 encryption","Deduplication and incremental snapshots","Support for many storage backends","Community support only"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Restic is a free, open-source command-line backup program first released in September 2015 under the BSD 2-Clause license, written in Go and maintained by original author Alexander Neumann along with an active GitHub community.$q$, $q$It runs as a single static binary with no server or database required, and is designed for developers and sysadmins who need scriptable, verifiable, encrypted backups across a wide range of storage backends.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Restic's design centers on content-defined chunking for deduplication, client-side AES-256 encryption, and snapshot-based incremental backups, plus built-in commands to verify that backups are actually restorable.$q$, $q$It supports many storage backends including local disks, SFTP, a REST server, Amazon S3, Backblaze B2, Azure Blob Storage, Google Cloud Storage, and dozens more via its rclone integration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Restic is entirely free and open source with no paid tiers, subscriptions, or company behind it. There is no cost for the software itself.$q$, $q$The only costs users incur come from whichever storage backend they choose to back up to, such as cloud object storage fees for S3 or Backblaze B2.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('38c4934d-5e31-4ebe-b4ec-4ca3760270e4', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Simultaneous multistreaming$q$, $q$Broadcast one live stream to 30+ destinations at once, including YouTube, Twitch, Facebook, and LinkedIn.$q$, 0);
