INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$What is Restream used for?$q$, $q$Restream is used to broadcast a single live video stream to multiple platforms simultaneously, such as YouTube, Twitch, and Facebook at once.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Is Restream free?$q$, $q$Yes, Restream offers a free plan supporting 2 simultaneous channels with Restream branding included.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$How much does Restream cost?$q$, $q$Paid plans start at $19/month (Standard) and go up to $239/month (Business), with custom Enterprise pricing above that.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$What is Restream Studio?$q$, $q$Restream Studio is a browser-based live production tool for multi-guest streams that requires no separate broadcasting software.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Can I stream to YouTube and Twitch at the same time with Restream?$q$, $q$Yes, Restream supports simultaneous streaming to more than 30 destinations including YouTube and Twitch.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Does Restream record my streams?$q$, $q$Yes, cloud recording is included on all paid plans.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Does Restream support 4K?$q$, $q$4K Ultra HD recording is available starting on the Professional plan.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$When was Restream founded?$q$, $q$Restream was founded in 2015 by Alexander Khuda and Andrew Surzhynskyi.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Independent streamers and podcasters$q$, $q$Multistream live shows to YouTube, Twitch, and X simultaneously to reach a wider audience.$q$, $q$Independent content creators and podcasters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Business webinars and product launches$q$, $q$Broadcast webinars and launches across multiple platforms at once to maximize reach.$q$, $q$Marketing and events teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Browser-based multi-guest production$q$, $q$Produce live, multi-guest shows using Restream Studio without extra broadcasting software.$q$, $q$Churches, event producers, and creators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Free$q$, $q$$0$q$, $q$free$q$, NULL, $q$["2 simultaneous channels","Restream branding included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Standard$q$, $q$$19/month ($16/month annual)$q$, $q$monthly or annual$q$, NULL, $q$["3 simultaneous channels","No branding","Guest channels"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Professional$q$, $q$$49/month ($39/month annual)$q$, $q$monthly or annual$q$, NULL, $q$["5 simultaneous channels","Full HD 1080p streaming","4K Ultra HD recording","Dual-format streaming"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Business$q$, $q$$239/month ($199/month annual)$q$, $q$monthly or annual$q$, NULL, $q$["8 simultaneous channels","Branded website player (1,000 concurrent viewers)","2 team seats","Co-producer mode"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Custom channel limits","Dedicated support","Advanced team features"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Restream is a live-streaming and multistreaming platform founded in 2015 and headquartered in Austin, Texas, that lets a single live video source broadcast simultaneously to more than 30 platforms including YouTube, Twitch, Facebook, and LinkedIn.$q$, $q$It offers both integration with existing broadcasting software like OBS Studio and its own browser-based production tool, Restream Studio, for multi-guest live shows with no software install required.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include simultaneous multistreaming, cloud recording, stream analytics, and encrypted RTMPS delivery, with higher tiers adding 1080p and 4K recording, dual-format horizontal-plus-vertical streaming, and a branded website video player.$q$, $q$Restream Studio supports multi-guest video calls, screen sharing, and on-screen graphics for browser-based live production, while an optional Clips add-on generates AI short-form clips from live streams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('24fcbb9a-223c-4b44-b8fd-07484fe7b8e4', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Restream's Free plan supports 2 simultaneous channels with branding. Standard costs $19/month ($16/month annually) for 3 channels, Professional costs $49/month ($39/month annually) for 5 channels with 1080p and 4K recording, and Business costs $239/month ($199/month annually) for 8 channels plus a website player and team seats.$q$, $q$An Enterprise tier offers custom pricing, and an optional Clips add-on for AI-generated short-form video costs an additional $19-$59 per month depending on plan.$q$]::text[], 2);
